public class Duck
{
    private readonly IFlyBehavior _flyBehavior;
    private readonly IQuackBehavior _quackBehavior;
    private readonly IDisplayBehavior _displayBehavior;

    public Duck(
        IFlyBehavior flyBehavior,
        IQuackBehavior quackBehavior,
        IDisplayBehavior displayBehavior)
    {
        _flyBehavior = flyBehavior;
        _quackBehavior = quackBehavior;
        _displayBehavior = displayBehavior;
    }

    public void Fly()
    {
        _flyBehavior.Fly();
    }

    public void Quack()
    {
        _quackBehavior.Quack();
    }

    public void Display()
    {
        _displayBehavior.Display();
    }
}

public interface IFlyBehavior
{
    void Fly();
}

public interface IQuackBehavior
{
    void Quack();
}

public interface IDisplayBehavior
{
    void Display();
}

public class SimpleFlying : IFlyBehavior
{
    public void Fly()
    {
        Console.WriteLine("Simple flying...");
    }
}

public class JetFlying : IFlyBehavior
{
    public void Fly()
    {
        Console.WriteLine("Jet flying...");
    }
}

public class SimpleQuack : IQuackBehavior
{
    public void Quack()
    {
        Console.WriteLine("Quack!");
    }
}

public class NoQuack : IQuackBehavior
{
    public void Quack()
    {
        Console.WriteLine("...");
    }
}

public class DisplayAsText : IDisplayBehavior
{
    public void Display()
    {
        Console.WriteLine("Displaying as text.");
    }
}

public class DisplayAsGraphics : IDisplayBehavior
{
    public void Display()
    {
        Console.WriteLine("Displaying as graphics.");
    }
}

var duck = new Duck(
    new JetFlying(),
    new SimpleQuack(),
    new DisplayAsGraphics());

duck.Fly();
duck.Quack();
duck.Display();

