using System;

namespace Simple
{
    class Program // declare a class
    {
        static void Main()
        {
            Console.WriteLine("Hi there!");
        }
    }
}

public record Person(
    string FirstName,
    string LastName);

var person1 = new Person("John", "Smith");
var person2 = new Person("John", "Smith");

// Value equality
Console.WriteLine(person1 == person2); // True

// Create a modified copy
var person3 = person1 with
{
    LastName = "Doe"
};

Console.WriteLine(person3);
// Person { FirstName = John, LastName = Doe }

public class UserClass
{
    public string Name { get; set; } = string.Empty;
}

public record UserRecord(string Name);

var class1 = new UserClass { Name = "John" };
var class2 = new UserClass { Name = "John" };

Console.WriteLine(class1 == class2);
// False (reference equality)

var record1 = new UserRecord("John");
var record2 = new UserRecord("John");

Console.WriteLine(record1 == record2);
// True (value equality)

